import{B as e}from"./BaseBreadcrumbs-D2EQ1GoT.js";import{d as i,c as o,a as t,b as s,e as c,w as v,h as r,i as f,k as b,_ as l}from"./index-CIW3DgOy.js";const p={class:"guarantee-view"},u={class:"container"},m={class:"guarantee-cta"},g=i({__name:"GuaranteeView",setup(_){const d=[{label:"Главная",to:"/"},{label:"Гарантия"}];return(h,a)=>{const n=r("router-link");return f(),o("main",p,[t("div",u,[s(e,{items:d}),a[3]||(a[3]=c('<h1 class="page-title" data-v-8384bdf2>Гарантии</h1><section class="guarantee-intro" data-v-8384bdf2><p data-v-8384bdf2> Компания «ГрузЭкспресс» несёт полную ответственность за сохранность вашего груза и гарантирует выполнение всех обязательств. Мы дорожим репутацией и делаем всё, чтобы каждый клиент остался доволен качеством наших услуг. </p></section><section class="guarantee-section" data-v-8384bdf2><h2 data-v-8384bdf2>Гарантия сохранности груза</h2><p data-v-8384bdf2> Мы гарантируем полную сохранность груза на всех этапах транспортировки — от момента погрузки до доставки по месту назначения. Каждый заказ сопровождается ответственным лицом, а все транспортные средства оснащены системами видеонаблюдения и контроля безопасности. </p><p data-v-8384bdf2> Перед началом перевозки наши специалисты проводят оценку состояния упаковки и составляют опись вложений. Это позволяет однозначно зафиксировать первоначальное состояние груза и исключить любые спорные ситуации. </p></section><section class="insurance-section" data-v-8384bdf2><h2 data-v-8384bdf2>Страхование</h2><p data-v-8384bdf2> Все заказы на перевозку автоматически застрахованы на сумму до 100 000 ₽ без дополнительной оплаты. Если стоимость вашего груза превышает эту сумму, мы предлагаем расширенное страхование по выгодным тарифам — от 0,1% от объявленной стоимости. </p><p data-v-8384bdf2> Страхование покрывает полный спектр рисков: повреждение, утрату, хищение, непредвиденные обстоятельства. В случае наступления страхового случая мы берём на себя все вопросы по оформлению и получению компенсации. </p><div class="insurance-features" data-v-8384bdf2><div class="insurance-item" data-v-8384bdf2><span class="insurance-icon" data-v-8384bdf2>🛡️</span><div data-v-8384bdf2><strong data-v-8384bdf2>Базовое страхование</strong><span data-v-8384bdf2>Включено во все заказы на сумму до 100 000 ₽</span></div></div><div class="insurance-item" data-v-8384bdf2><span class="insurance-icon" data-v-8384bdf2>💎</span><div data-v-8384bdf2><strong data-v-8384bdf2>Расширенное страхование</strong><span data-v-8384bdf2>Полное покрытие стоимости груза от 0,1%</span></div></div><div class="insurance-item" data-v-8384bdf2><span class="insurance-icon" data-v-8384bdf2>📋</span><div data-v-8384bdf2><strong data-v-8384bdf2>Быстрое оформление</strong><span data-v-8384bdf2>Страховой полис оформляется за 5 минут</span></div></div></div></section><section class="compensation-section" data-v-8384bdf2><h2 data-v-8384bdf2>Компенсация в случае ущерба</h2><p data-v-8384bdf2> В случае повреждения или утраты груза мы гарантируем полную компенсацию документально подтверждённой стоимости. Рассмотрение претензий и выплата компенсации осуществляется в срок до 14 рабочих дней. </p><p data-v-8384bdf2> Наша компания имеет безупречную репутацию в сфере урегулирования претензий. За всё время работы нами была выплачена компенсация по каждому обоснованному случаю обращения клиентов. </p></section><section class="warranty-section" data-v-8384bdf2><h2 data-v-8384bdf2>Гарантийные обязательства по срокам</h2><p data-v-8384bdf2> Мы гарантируем доставку в оговорённые сроки. Если груз не был доставлен вовремя по нашей вине, мы возвращаем до 30% стоимости перевозки. Для постоянных клиентов и при регулярных перевозках действуют особые условия гарантийных обязательств. </p><p data-v-8384bdf2> В случае форс-мажорных обстоятельств (стихийные бедствия, дорожные блокировки) сроки доставки могут быть сдвинуты. В таких ситуациях мы своевременно информируем клиента и предлагаем альтернативные маршруты. </p></section><section class="claims-section" data-v-8384bdf2><h2 data-v-8384bdf2>Порядок подачи претензий</h2><p data-v-8384bdf2> Если у вас возникли вопросы по качеству услуги или претензии к сохранности груза, вы можете подать письменную претензию одним из следующих способов: </p><ol class="claims-list" data-v-8384bdf2><li data-v-8384bdf2><strong data-v-8384bdf2>Через личный кабинет:</strong> перейдите в раздел «Мои заказы», выберите нужный заказ и нажмите «Подать претензию». Приложите фотографии повреждений и подробное описание проблемы. </li><li data-v-8384bdf2><strong data-v-8384bdf2>По электронной почте:</strong> отправьте претензию на адрес claims@gruzexpress.ru с указанием номера заказа и подробным описанием ситуации. </li><li data-v-8384bdf2><strong data-v-8384bdf2>Лично в офисе:</strong> подайте претензию в любой из наших офисов с документом, удостоверяющим личность, и номером заказа. </li><li data-v-8384bdf2><strong data-v-8384bdf2>По телефону поддержки:</strong> позвоните на горячую линию +7 (800) 555-35-35 для устной регистрации претензии. </li></ol><p data-v-8384bdf2> Срок рассмотрения претензии — не более 14 рабочих дней с момента получения. Мы свяжемся с вами для информирования о результатах рассмотрения и принятия решения о компенсации. </p></section>',7)),t("section",m,[a[1]||(a[1]=t("h2",null,"Остались вопросы о гарантиях?",-1)),a[2]||(a[2]=t("p",null,"Наши специалисты готовы проконсультировать вас по всем вопросам гарантий и страхования.",-1)),s(n,{to:"/contacts",class:"cta-btn"},{default:v(()=>[...a[0]||(a[0]=[b("Связаться с нами",-1)])]),_:1})])])])}}}),B=l(g,[["__scopeId","data-v-8384bdf2"]]);export{B as default};
